#include <BC/BCException.h>


///////////////////////////////////////////////////////////////////////////////
// Namespace: BC
///////////////////////////////////////////////////////////////////////////////

namespace BC
{

///////////////////////////////////////////////////////////////////////////////
// BCException
///////////////////////////////////////////////////////////////////////////////

BCException::BCException(const BCException &other)
{
	m_where = other.m_where;
	m_message = other.m_message;
}

BCException::BCException(
	const char *where_,
	const char *message)
{
	m_where = where_;
	m_message = message;
}

const BCPString &BCException::GetWhere() const
{
	return m_where;
}

const BCPString &BCException::GetMsg() const
{
	return m_message;
}

///////////////////////////////////////////////////////////////////////////////
// Namespace: BC
///////////////////////////////////////////////////////////////////////////////

} // End of namespace BC

